import{_ as d,C as l,o as c,c as p,ai as n,E as e,w as t,a as o}from"./chunks/framework.BH_J6TYN.js";const C=JSON.parse('{"title":"Carrito y WhatsApp","description":"El carrito de compras que envía el pedido completo por WhatsApp","frontmatter":{"title":"Carrito y WhatsApp","description":"El carrito de compras que envía el pedido completo por WhatsApp"},"headers":[],"relativePath":"cat/carrito-whatsapp.md","filePath":"cat/carrito-whatsapp.md"}'),u={name:"cat/carrito-whatsapp.md"};function h(m,a,g,b,q,f){const r=l("Step"),i=l("Steps"),s=l("Warning");return c(),p("div",null,[a[6]||(a[6]=n('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>El carrito de SYNTIcat permite que tus clientes seleccionen varios productos, elijan variantes (talla, color), revisen su pedido y te lo envíen completo por WhatsApp. No es un checkout con pasarela de pago — es un <strong>carrito que genera un mensaje de WhatsApp</strong> con el pedido listo.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p><strong>En la landing (lo que ve tu cliente):</strong></p><ul><li>Botón <strong>&quot;Agregar al carrito&quot;</strong> en cada tarjeta de producto</li><li><strong>Cart Drawer</strong> (panel lateral derecho) que se desliza al agregar un producto</li><li>Botón <strong>&quot;Finalizar pedido&quot;</strong> dentro del drawer</li></ul><p><strong>Configuración:</strong> Se activa automáticamente en los planes Semestral y Anual. No requiere configuración adicional.</p><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><h3 id="flujo-del-carrito" tabindex="-1">Flujo del carrito <a class="header-anchor" href="#flujo-del-carrito" aria-label="Permalink to &quot;Flujo del carrito&quot;">​</a></h3>',8)),e(i,null,{default:t(()=>[e(r,{title:"El cliente navega el catálogo"},{default:t(()=>[...a[0]||(a[0]=[o(" Ve todos los productos con fotos y precios. ",-1)])]),_:1}),e(r,{title:"Agrega al carrito"},{default:t(()=>[...a[1]||(a[1]=[o(' Toca **"Agregar al carrito"** en cada producto. Si tiene variantes (talla, color), las elige antes de agregar. ',-1)])]),_:1}),e(r,{title:"Cart Drawer se abre"},{default:t(()=>[...a[2]||(a[2]=[o(" Un panel lateral se desliza desde la derecha mostrando los productos en el carrito, cantidades y total. ",-1)])]),_:1}),e(r,{title:"Revisa el carrito"},{default:t(()=>[...a[3]||(a[3]=[o(" Puede cambiar cantidades, eliminar productos y ver el total actualizado. ",-1)])]),_:1}),e(r,{title:"Checkout por WhatsApp"},{default:t(()=>[...a[4]||(a[4]=[o(' Toca **"Finalizar pedido"** → Se abre WhatsApp con el mensaje completo incluyendo productos, variantes, cantidades y total. ',-1)])]),_:1})]),_:1}),a[7]||(a[7]=n(`<h3 id="formato-del-mensaje-de-whatsapp" tabindex="-1">Formato del mensaje de WhatsApp <a class="header-anchor" href="#formato-del-mensaje-de-whatsapp" aria-label="Permalink to &quot;Formato del mensaje de WhatsApp&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🛍️ Nuevo pedido SYNTIcat</span></span>
<span class="line"><span>📦 Orden: SC-0047</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Productos:</span></span>
<span class="line"><span>• 1× Camisa polo azul (Talla M) — REF 15.00</span></span>
<span class="line"><span>• 2× Correa de cuero marrón — REF 8.00 c/u</span></span>
<span class="line"><span></span></span>
<span class="line"><span>💰 Total: REF 31.00</span></span>
<span class="line"><span>   Bs. 1,131.50</span></span></code></pre></div><h3 id="cart-drawer-panel-lateral" tabindex="-1">Cart Drawer (panel lateral) <a class="header-anchor" href="#cart-drawer-panel-lateral" aria-label="Permalink to &quot;Cart Drawer (panel lateral)&quot;">​</a></h3><p>El carrito aparece como un panel que se desliza desde la derecha. El cliente puede:</p><ul><li>Ver todos los productos seleccionados</li><li>Modificar cantidades</li><li>Eliminar productos</li><li>Ver el total en tiempo real</li><li>Sin cerrar el catálogo — navega y agrega simultáneamente</li></ul><h3 id="plan-basico-sin-carrito" tabindex="-1">Plan Básico (sin carrito) <a class="header-anchor" href="#plan-basico-sin-carrito" aria-label="Permalink to &quot;Plan Básico (sin carrito)&quot;">​</a></h3><p>En el plan Básico no hay carrito. Cada producto tiene un botón <strong>&quot;Consultar por WhatsApp&quot;</strong> que abre WhatsApp directamente con un mensaje sobre ese producto individual.</p><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li><strong>No procesa pagos</strong> — no tiene Stripe, PayPal ni ninguna pasarela</li><li><strong>No pide datos del cliente</strong> — no hay formulario de dirección, nombre, etc.</li><li><strong>No calcula envío</strong> — no tiene integración con delivery</li><li><strong>No tiene cupones ni descuentos</strong> automáticos</li><li><strong>No es persistente</strong> — el carrito usa localStorage; si el cliente borra datos del navegador, se pierde</li><li><strong>No tiene lista de deseos / favoritos</strong></li><li><strong>No envía confirmación automática</strong> al cliente</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Básico</th><th>Semestral</th><th>Anual</th></tr></thead><tbody><tr><td>Carrito de compras</td><td>❌ (solo botón WA directo)</td><td>✅ Carrito básico</td><td>✅ Carrito completo</td></tr><tr><td>Cart Drawer lateral</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Código SC-XXXX</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>Variantes en carrito</td><td>❌</td><td>✅ (talla/color)</td><td>✅ (todas)</td></tr></tbody></table><h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-tienda-electrove-en-barquisimeto" tabindex="-1">Caso: Tienda &quot;ElectroVE&quot; en Barquisimeto <a class="header-anchor" href="#caso-tienda-electrove-en-barquisimeto" aria-label="Permalink to &quot;Caso: Tienda &quot;ElectroVE&quot; en Barquisimeto&quot;">​</a></h3><p>Miguel vende accesorios electrónicos con plan Semestral:</p><ol><li>Un cliente entra al catálogo</li><li>Agrega &quot;Auriculares Bluetooth&quot; (REF 20) → se abre el Cart Drawer</li><li>Agrega &quot;Cable USB-C&quot; (REF 5) y &quot;Funda para celular&quot; (REF 8, color negro)</li><li>En el drawer ve: 3 productos, Total REF 33.00</li><li>Toca &quot;Finalizar pedido&quot; → WhatsApp se abre con el mensaje completo</li><li>Miguel recibe el pedido, confirma stock y coordina pago por Pago Móvil</li></ol>`,15)),e(s,null,{default:t(()=>[...a[5]||(a[5]=[o(" SYNTIweb **no cobra a los clientes**. El carrito genera el mensaje de WhatsApp — el pago se coordina entre el negocio y el cliente directamente. ",-1)])]),_:1}),a[8]||(a[8]=n('<h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/cat/mini-order-sc.html">Mini Order (SC-XXXX)</a> — Códigos de seguimiento de pedidos</li><li><a href="/cat/catalogo-productos.html">Catálogo de productos</a> — Gestión completa de productos</li><li><a href="/shared/whatsapp.html">WhatsApp</a> — Cómo funciona el canal de comunicación</li></ul>',2))])}const v=d(u,[["render",h]]);export{C as __pageData,v as default};
